+#[cfg(test)]
+mod tests {
+    use super::*;
+    use tempfile::TempDir;
+
+    // =========================================================================
+    // ensure_dir tests
+    // =========================================================================
+
+    #[test]
+    fn ensure_dir_creates_new_directory() {
+        let temp = TempDir::new().unwrap();
+        let dir = temp.path().join("new_dir");
+
+        assert!(!dir.exists());
+        ensure_dir(&dir).unwrap();
+        assert!(dir.exists());
+        assert!(dir.is_dir());
+    }
+
+    #[test]
+    fn ensure_dir_creates_nested_directories() {
+        let temp = TempDir::new().unwrap();
+        let dir = temp.path().join("a").join("b").join("c");
+
+        assert!(!dir.exists());
+        ensure_dir(&dir).unwrap();
+        assert!(dir.exists());
+        assert!(dir.is_dir());
+    }
+
+    #[test]
+    fn ensure_dir_noop_if_exists() {
+        let temp = TempDir::new().unwrap();
+        let dir = temp.path().join("existing");
+        std::fs::create_dir(&dir).unwrap();
+
+        // Should not fail if directory exists
+        ensure_dir(&dir).unwrap();
+        assert!(dir.exists());
+    }
+
+    #[test]
+    fn ensure_dir_idempotent() {
+        let temp = TempDir::new().unwrap();
+        let dir = temp.path().join("idem");
+
+        // Call multiple times
+        ensure_dir(&dir).unwrap();
+        ensure_dir(&dir).unwrap();
+        ensure_dir(&dir).unwrap();
+        assert!(dir.exists());
+    }
+
+    // =========================================================================
+    // read_optional tests
+    // =========================================================================
+
+    #[test]
+    fn read_optional_existing_file() {
+        let temp = TempDir::new().unwrap();
+        let file = temp.path().join("test.txt");
+        std::fs::write(&file, "hello world").unwrap();
+
+        let result = read_optional(&file).unwrap();
+        assert!(result.is_some());
+        assert_eq!(result.unwrap(), "hello world");
+    }
+
+    #[test]
+    fn read_optional_nonexistent_file() {
+        let temp = TempDir::new().unwrap();
+        let file = temp.path().join("nonexistent.txt");
+
+        let result = read_optional(&file).unwrap();
+        assert!(result.is_none());
+    }
+
+    #[test]
+    fn read_optional_empty_file() {
+        let temp = TempDir::new().unwrap();
+        let file = temp.path().join("empty.txt");
+        std::fs::write(&file, "").unwrap();
+
+        let result = read_optional(&file).unwrap();
+        assert!(result.is_some());
+        assert_eq!(result.unwrap(), "");
+    }
+
+    #[test]
+    fn read_optional_with_unicode() {
+        let temp = TempDir::new().unwrap();
+        let file = temp.path().join("unicode.txt");
+        std::fs::write(&file, "日本語🚀").unwrap();
+
+        let result = read_optional(&file).unwrap();
+        assert!(result.is_some());
+        assert_eq!(result.unwrap(), "日本語🚀");
+    }
+
+    #[test]
+    fn read_optional_multiline() {
+        let temp = TempDir::new().unwrap();
+        let file = temp.path().join("multiline.txt");
+        std::fs::write(&file, "line1\nline2\nline3").unwrap();
+
+        let result = read_optional(&file).unwrap();
+        assert!(result.is_some());
+        assert!(result.unwrap().contains('\n'));
+    }
+}

@@ -12,3 +12,59 @@ pub fn current_branch() -> Result<Option<String>> {
 pub fn is_repo(path: impl AsRef<std::path::Path>) -> bool {
     path.as_ref().join(".git").exists()
 }
+
+#[cfg(test)]
+mod tests {
+    use super::*;
+    use tempfile::TempDir;
+
+    // =========================================================================
+    // current_branch tests
+    // =========================================================================
+
+    #[test]
+    fn current_branch_returns_none_stub() {
+        // Note: This is a stub that returns None
+        let result = current_branch().unwrap();
+        assert!(result.is_none());
+    }
+
+    // =========================================================================
+    // is_repo tests
+    // =========================================================================
+
+    #[test]
+    fn is_repo_with_git_directory() {
+        let temp = TempDir::new().unwrap();
+        let git_dir = temp.path().join(".git");
+        std::fs::create_dir(&git_dir).unwrap();
+
+        assert!(is_repo(temp.path()));
+    }
+
+    #[test]
+    fn is_repo_without_git_directory() {
+        let temp = TempDir::new().unwrap();
+
+        assert!(!is_repo(temp.path()));
+    }
+
+    #[test]
+    fn is_repo_with_git_file_not_dir() {
+        let temp = TempDir::new().unwrap();
+        let git_file = temp.path().join(".git");
+        // Create a file named .git instead of a directory
+        std::fs::write(&git_file, "gitdir: ../other").unwrap();
+
+        // A .git file (worktree) should also count as a repo
+        assert!(is_repo(temp.path()));
+    }
+
+    #[test]
+    fn is_repo_nonexistent_path() {
+        let temp = TempDir::new().unwrap();
+        let nonexistent = temp.path().join("nonexistent");
+
+        assert!(!is_repo(&nonexistent));
+    }
+}
